"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[21996],{14059:(e,a,t)=>{t.r(a),t.d(a,{assets:()=>d,contentTitle:()=>i,default:()=>l,frontMatter:()=>r,metadata:()=>o,toc:()=>c});var o=t(67870),n=t(74848),s=t(28453);const r={slug:"the-lost-era-of-pokemon-cards",title:"The Lost Era of Pok\xe9mon Cards",date:new Date("2026-03-27T00:00:00.000Z"),image:"/blog/2026-03-27-before-the-pokemon-tcg-the-lost-era-of-pokemon-cards.webp",tags:["pokemon","collecting","pokemon-cards"],description:"Most people think the Pok\xe9mon Trading Card Game is where it all started. It's not. Before the TCG became the global standard, Japan had an entire parallel ecosystem of Pok\xe9mon cards.",hideSidebar:!0},i=void 0,d={authorsImageUrls:[]},c=[{value:"Carddass (1996\u20132000)",id:"carddass-19962000",level:2},{value:"Topsun (1997)",id:"topsun-1997",level:2},{value:"Meiji (1997\u20132002)",id:"meiji-19972002",level:2},{value:"Tomy Scratch Cards (1997)",id:"tomy-scratch-cards-1997",level:2},{value:"Pok\xe9mon Kids Mini Cards (1996\u20131997)",id:"pok\xe9mon-kids-mini-cards-19961997",level:2},{value:"Nissui Battle Seals (1999)",id:"nissui-battle-seals-1999",level:2},{value:"What Actually Happened",id:"what-actually-happened",level:2}];function h(e){const a={a:"a",h2:"h2",p:"p",strong:"strong",...(0,s.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(a.p,{children:"Most people think that WOTC Pok\xe9mon Trading Card Game is where it all started. I know I did."}),"\n",(0,n.jsx)(a.p,{children:"But it's not. Before the TCG became the global standard, Japan had an entire parallel ecosystem of Pok\xe9mon cards \u2014 different companies, different distribution channels, different philosophies about what a card should even be."}),"\n",(0,n.jsx)(a.p,{children:"I went down this rabbit hole, so you won't have to."}),"\n",(0,n.jsx)(a.h2,{id:"carddass-19962000",children:"Carddass (1996\u20132000)"}),"\n",(0,n.jsx)(a.p,{children:(0,n.jsx)(a.strong,{children:"The Actual First Pok\xe9mon Cards"})}),"\n",(0,n.jsxs)(a.p,{children:["The first Pok\xe9mon cards didn't come from a game store. ",(0,n.jsx)(a.a,{href:"https://pokeboon.com/about-the-series-of-a-bandai-pokemon-carddass/",children:"They came out of a vending machine"}),". Bandai released the Carddass series in September 1996, a full month before the TCG launched, five cards for \xa5100, or a single card for \xa520."]}),"\n",(0,n.jsx)(a.p,{children:"The machines were called Carddass, Bandai's term for their card vending infrastructure, and they were everywhere in Japan at the time."}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.a,{href:"https://cardgamer.com/features/cardass-pokemon-cards/",children:"Bandai produced four sets of Carddass Pok\xe9mon cards between 1996 and 1997"}),", with a consistent layout: Pok\xe9mon on the front, information on the back. Unlike the TCG, which abstracts Pok\xe9mon into a battle system, the backs showed evolution trees and each Pok\xe9mon's encounter rates across Red, Green, and Blue. They were documenting the game world."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"Part 1 and Part 2"})," were based on Pok\xe9mon Red and Green. ",(0,n.jsx)(a.a,{href:"https://pokeboon.com/about-the-series-of-a-bandai-pokemon-carddass/",children:"Together they totalled 309 cards \u2014 more than any other Carddass release"}),". ",(0,n.jsx)(a.a,{href:"https://bulbapedia.bulbagarden.net/wiki/Bandai_Pok%C3%A9mon_Carddass_Cards",children:"The artwork was still early-stage, as the world and characters weren't yet as fully developed as they'd later become"}),"."]}),"\n",(0,n.jsx)(a.p,{children:"These are the cards most collectors refer to when they talk about Carddass."}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"Part 3 and Part 4"})," shifted toward more dynamic depictions, ",(0,n.jsx)(a.a,{href:"https://bulbapedia.bulbagarden.net/wiki/Bandai_Pok%C3%A9mon_Carddass_Cards",children:"emphasizing action and appealing to collectors' imaginations"}),". They had a smaller card count, but introduced secret promotional cards. ",(0,n.jsx)(a.a,{href:"https://pokeboon.com/about-the-series-of-a-bandai-pokemon-carddass/",children:"The Part 3 secret \u2014 FILE NO.000 \u2014 was distributed only at CoroCoro Plaza inside Ito-Yokado department stores in April 1997. The Part 4 secret was available only through vending machines at that same location starting in June 1997"}),". A handful of stores, a short window. Even at the time, these were essentially impossible to find."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"The Jumbo Carddass"})," was a separate release from November 1996. ",(0,n.jsx)(a.a,{href:"https://cardgamer.com/features/cardass-pokemon-cards/",children:"These larger cards featured removable stickers on the front, trainer details from Red/Green/Blue, and a map of Kanto on the back. Some included snapshots of in-game battles"}),". ",(0,n.jsx)(a.a,{href:"https://pokeboon.com/about-the-series-of-a-bandai-pokemon-carddass/",children:"A special Jumbo Pikachu promo was given to attendees of the 1997 Tokyo Toy Show at Tokyo Big Sight in March of that year"}),"."]}),"\n",(0,n.jsxs)(a.p,{children:["After the game-based sets, ",(0,n.jsx)(a.a,{href:"https://bulbapedia.bulbagarden.net/wiki/Bandai_Pok%C3%A9mon_Carddass_Cards",children:"Bandai shifted Carddass production toward anime scenes and movie tie-ins, continuing through 2000 with content covering the Gold and Silver era and Generation II Pok\xe9mon"}),"."]}),"\n",(0,n.jsxs)(a.p,{children:["One practical issue across all Carddass releases: ",(0,n.jsx)(a.a,{href:"https://bulbapedia.bulbagarden.net/wiki/Bandai_Pok%C3%A9mon_Carddass_Cards",children:"the cardboard stock was delicate, and in 1996 there was little knowledge about how to safely store collectible cards. Most surviving copies have creases or smudges, which makes clean examples significantly more valuable"}),". A PSA 10 Charizard from the Red series has sold for over $30,000."]}),"\n",(0,n.jsx)(a.h2,{id:"topsun-1997",children:"Topsun (1997)"}),"\n",(0,n.jsx)(a.p,{children:(0,n.jsx)(a.strong,{children:"The Most Misunderstood Cards in the Hobby"})}),"\n",(0,n.jsxs)(a.p,{children:["Topsun cards came packaged with apple-flavored bubble gum from a Japanese candy company called Top-Seika. ",(0,n.jsx)(a.a,{href:"https://pokeboon.com/what-is-the-pokemon-topsun-card/",children:"Each pack contained two cards and two sticks of gum and cost 60 yen"}),". They covered the first 150 Pok\xe9mon, no Mew, and the design was clean and encyclopedic, closer to a physical Pok\xe9dex than anything else."]}),"\n",(0,n.jsxs)(a.p,{children:["The controversy around these cards comes down to one thing: the copyright date printed on the card reads 1995. That date doesn't refer to when the cards were made. ",(0,n.jsx)(a.a,{href:"https://sleevenocardbehind.com/a-guide-to-topsun-pokemon-cards/",children:"It reflects the Pok\xe9mon property's copyright, not the Topsun cards themselves. The official Top Seika website states that a licensing agreement wasn't established until 1997"}),". ",(0,n.jsx)(a.a,{href:"https://www.slab-z.com/post/the-rise-of-pok%C3%A9mon-topsun-cards-controversy-and-rarity",children:"CGC and BGS have since updated their grading practices to reflect the 1997 release date"}),", and PSA followed in March 2024."]}),"\n",(0,n.jsx)(a.p,{children:"Within Topsun there are essentially three distinct print runs, and they matter a lot to collectors:"}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"Blue Back / No Number"})," \u2014 ",(0,n.jsx)(a.a,{href:"https://sleevenocardbehind.com/a-guide-to-topsun-pokemon-cards/",children:"Early in production, an error occurred where the Pok\xe9dex number was missing from the face of each card. The error was corrected quickly, but many made it into circulation"}),". Only 50 of the 150 Pok\xe9mon have a confirmed no-number variant, and all of them are blue backs. These are considered the very first print run. The Charizard no-number PSA 10 sold for $493,230 in 2021 \u2014 one of three known to exist at that grade."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"Blue Back / Numbered"})," \u2014 The corrected first wave, still on blue stock. ",(0,n.jsx)(a.a,{href:"https://cardmavin.com/articles/japanese-topsun-set-list",children:"Blue backs are considered the earlier print and are more coveted than green backs"}),". ",(0,n.jsx)(a.a,{href:"https://www.goingtwice.com/blogs/pokemon/topsun-cards",children:"The cards came loose in gum packets with no protection and were never meant to be collected, so mint copies are extremely hard to find"}),"."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"Green Back"})," \u2014 ",(0,n.jsx)(a.a,{href:"https://cardmavin.com/articles/japanese-topsun-set-list",children:"Later print runs switched to green card backs"}),". Same Pok\xe9mon, same artwork, but considered a second wave and generally less rare than blue backs."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"Prism Holofoils"})," \u2014 ",(0,n.jsx)(a.a,{href:"https://cardmavin.com/articles/japanese-topsun-set-list",children:"Sixteen of the 150 Pok\xe9mon have a prism holo version, released after the initial print run at a rate of one holo per 40 packs"}),". Charizard and Pikachu are the most valuable. These exist only in the numbered format \u2014 there are no no-number holos."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.a,{href:"https://cardgamer.com/features/history-of-topsun-pokemon-cards/",children:'Topsun also produced "VS" cards from 1997 onward, featuring two Pok\xe9mon battling on the front rather than a single Pok\xe9mon with Pok\xe9dex data. These came in waves covering Generations 1 through 4, meaning production continued well into the mid-2000s. A branding change from "Topsun" to "Top" in 1998 helps date some of these later cards, but many are impossible to pin down precisely'}),". The VS cards are a completely different product from the blue and green backs, and most collectors treat them as separate."]}),"\n",(0,n.jsx)(a.h2,{id:"meiji-19972002",children:"Meiji (1997\u20132002)"}),"\n",(0,n.jsx)(a.p,{children:(0,n.jsx)(a.strong,{children:"Chocolate Cards With an Actual Game Mechanic"})}),"\n",(0,n.jsxs)(a.p,{children:["The Meiji series gets dismissed as simple promotional cards. That's underselling them. ",(0,n.jsx)(a.a,{href:"https://pokumon.com/meiji-chocolate-pokemon-promotion/",children:"Starting in 1997, Meiji packaged collectible Pok\xe9mon cards with their chocolate, making them one of the earliest brand collaborators with the franchise. The collaboration ran through 2002, producing eight distinct sets"}),". Each one was different enough from the last that collecting the full run is genuinely its own project."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"1997 Set"})," \u2014 ",(0,n.jsx)(a.a,{href:"https://pokumon.com/meiji-chocolate-pokemon-promotion/",children:'The first collaboration introduced "rock paper scissors" cards, where each card displayed an HP value and type on the front, with flavor information on the back. All cards were foil, with Mew and Mewtwo receiving additional gold foil versions'}),". ",(0,n.jsx)(a.a,{href:"https://pokevault.com/meiji-1997",children:"This initial series was large \u2014 over 150 cards \u2014 featuring characters like Eevee, the Eeveelutions, Mew, Mewtwo, Charizard, Blastoise, and Venusaur"}),". One card per box of chocolate."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"1998 Set"})," \u2014 ",(0,n.jsx)(a.a,{href:"https://pokumon.com/meiji-chocolate-pokemon-promotion/",children:"Meiji continued the rock paper scissors mechanic, but tied the cards to the first Pok\xe9mon movie and its accompanying short. The Pok\xe9mon's Japanese names were spelled out in R\u014dmaji \u2014 English lettering \u2014 which was unusual for the era"}),"."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"2000 Sets (Blue, Silver, and Gold)"})," \u2014 ",(0,n.jsx)(a.a,{href:"https://pokumon.com/meiji-chocolate-pokemon-promotion/",children:"The 2000 release was the largest Meiji set to that point, bringing back the rock paper scissors game alongside blue, silver, and gold patterned holofoil variants. The backs also included move data showing what levels Pok\xe9mon learned specific attacks"}),". ",(0,n.jsx)(a.a,{href:"https://pokumon.com/meiji-chocolate-pokemon-promotion/",children:"Only Pikachu received all three color variants; every other Pok\xe9mon appeared in just one. It was also the first Meiji set to include Generation II Pok\xe9mon like Espeon and Umbreon"}),". Lugia \u2014 the face of Pok\xe9mon Silver \u2014 only got a gold foil version, which is a choice that's never quite been explained."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"2001 Set"})," \u2014 ",(0,n.jsx)(a.a,{href:"https://pokumon.com/meiji-chocolate-pokemon-promotion/",children:"Meiji dropped the rock paper scissors mechanic and switched to a horizontal rainbow holofoil. The cards are extremely reflective with an almost hologram effect \u2014 a foil treatment that would later appear in the Japanese TCG's Platinum Arceus era"}),". The 2001 set reused some 2000 artwork alongside new Pok\xe9mon like Marill."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.strong,{children:"2002 VS Series"})," \u2014 ",(0,n.jsx)(a.a,{href:"https://pokumon.com/meiji-chocolate-pokemon-promotion/",children:"The final year of Meiji's original Pok\xe9mon run was a significant departure. Each card featured an embossed battle scene between two Pok\xe9mon, with their names displayed on colored bars along the side"}),". Cards came in different color variants depending on which Pok\xe9mon was featured \u2014 though whether one variant is rarer than the other isn't definitively documented."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.a,{href:"https://www.goingtwice.com/blogs/pokemon/meiji-the-pokemon-cards-you-didnt-know-you-needed",children:"Across all years, the cards were printed on shorter, heavier card stock unique to Meiji, with finishes that changed from year to year. They were loose in boxes of chocolate, edges and surfaces damage easily, and they were never meant to be sleeved and stored"}),". A full master set across all eight releases, in collectible condition, barely exists. Individual subsets are poorly documented and some have almost no English-language checklists at all."]}),"\n",(0,n.jsx)(a.h2,{id:"tomy-scratch-cards-1997",children:"Tomy Scratch Cards (1997)"}),"\n",(0,n.jsx)(a.p,{children:(0,n.jsx)(a.strong,{children:"Designed to Be Destroyed"})}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.a,{href:"https://www.goingtwice.com/blogs/pokemon/tomy-scratch-cards",children:"Unlike Topsun and Carddass, the Tomy scratch cards weren't collectibles. They were meant to be played"}),". Each card had a scratch-off surface on the back, like a lottery ticket, that revealed Pok\xe9mon data during gameplay. ",(0,n.jsx)(a.a,{href:"https://www.yamwax.com/tomy-scratch/faq/",children:"Players each drew a random card from their pack, flipped a coin to decide who went first, scratched panels to reveal moves and damage values, and subtracted HP until one Pok\xe9mon hit zero. Then you moved to the next card"}),"."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.a,{href:"https://www.yamwax.com/tomy-scratch/",children:"Tomy released Series 1 in May 1997, with 36 total cards including six holofoils \u2014 Charizard and Pikachu among them"}),". ",(0,n.jsx)(a.a,{href:"https://www.goingtwice.com/blogs/pokemon/tomy-scratch-cards",children:"Series 2 followed later that year. Both series feature artwork by Ken Sugimori and Mitsuhiro Arita, including the Kangaskhan trophy card art"}),". Packs came with five cards each, sold in retail boxes."]}),"\n",(0,n.jsxs)(a.p,{children:["The two series are broadly similar in design but differ in their Pok\xe9mon lineup and holo distribution. ",(0,n.jsx)(a.a,{href:"https://www.goingtwice.com/blogs/pokemon/tomy-scratch-cards",children:"Holofoil cards can sometimes be duplicated within the same box, which makes chasing specific holos unpredictable"}),". Series 2 packs command higher prices today \u2014 sealed Series 1 packs rarely sell under $250, and Series 2 goes higher."]}),"\n",(0,n.jsxs)(a.p,{children:["Here's the collecting paradox: ",(0,n.jsx)(a.a,{href:"https://www.goingtwice.com/blogs/pokemon/tomy-scratch-cards",children:"since scratching was essential to playing, unscratched cards are extremely rare to find"}),". ",(0,n.jsx)(a.a,{href:"https://www.yamwax.com/tomy-scratch/faq/",children:'PSA now designates each graded card as "scratched" or "unscratched," with unscratched examples commanding a significant premium'}),". A scratched Tomy card was used exactly as intended. An unscratched one was never played. The card in its natural final state is, from a collector's standpoint, damaged \u2014 a situation no other set in Pok\xe9mon history replicates."]}),"\n",(0,n.jsx)(a.h2,{id:"pok\xe9mon-kids-mini-cards-19961997",children:"Pok\xe9mon Kids Mini Cards (1996\u20131997)"}),"\n",(0,n.jsx)(a.p,{children:(0,n.jsx)(a.strong,{children:"The Forgotten Pok\xe9dex"})}),"\n",(0,n.jsx)(a.p,{children:'Bandai produced a separate line of miniature cards packaged with small Pok\xe9mon finger puppet figures as part of their "Kids" candy toy line. The cards are smaller than standard TCG cards and contain Pok\xe9dex-style data \u2014 similar informational philosophy to Carddass, but physically paired with a figure.'}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.a,{href:"https://swirlyeg.com/en-us/blogs/news/vintage-pokemon-card-sets",children:"The line launched in 1996 with 36 cards and eight finger puppets. The rarest card in this first wave is Charizard, and Bandai actually released two versions \u2014 one in October 1996 and one in December 1996. They look identical on the front, but the second version was updated to include more available finger puppet options on the back. A second wave followed in 1997, expanding the set to cover all 151 Pok\xe9mon"}),"."]}),"\n",(0,n.jsxs)(a.p,{children:[(0,n.jsx)(a.a,{href:"https://swirlyeg.com/en-us/blogs/news/vintage-pokemon-card-sets",children:"Because documentation on this set is so sparse, leading grading companies won't officially grade it"}),". It's largely absent from high-end collecting discussions \u2014 categorized as a toy accessory rather than a card product. But in terms of intent, it might be the most complete early attempt at a physical Pok\xe9dex: you weren't just collecting a card, you were collecting the Pok\xe9mon and its data as a single object."]}),"\n",(0,n.jsx)(a.h2,{id:"nissui-battle-seals-1999",children:"Nissui Battle Seals (1999)"}),"\n",(0,n.jsx)(a.p,{children:(0,n.jsx)(a.strong,{children:"Where the Definitions Break Down"})}),"\n",(0,n.jsx)(a.p,{children:'The Nissui products push at the edges of what we even call a "card." Nissui is a Japanese food company that distributed Pok\xe9mon-themed seals, technically stickers on thin cardboard, with their products in 1999. They were collected like cards, structured into sets, and designed around battle concepts.'}),"\n",(0,n.jsxs)(a.p,{children:["Whether they count depends entirely on your definition. Cardboard backing: yes. Gameplay mechanic: borderline. Collectible lore: absolutely. They sit in a category that resists easy labeling, which is part of why they're rarely discussed alongside the other pre-TCG products. They were also starting to gain traction with graders \u2014 ",(0,n.jsx)(a.a,{href:"https://dittodan.neocities.org/carddass",children:"CGC Trading Cards began officially grading Sealdass cards, and prices on ones that had been passed on earlier started climbing noticeably"}),"."]}),"\n",(0,n.jsx)(a.h2,{id:"what-actually-happened",children:"What Actually Happened"}),"\n",(0,n.jsx)(a.p,{children:"Looking at all of these together, what's striking is how differently each one thought about what a Pok\xe9mon card should be. Carddass documented the game world through vending machines. Topsun built a physical Pok\xe9dex in gum packs. Meiji added a playable game mechanic to chocolate promotions and reinvented the format every year. Tomy created a fully playable card game that required destroying the cards to use them. The Kids line paired physical figures with informational cards as a single object."}),"\n",(0,n.jsx)(a.p,{children:"None of them were doing the same thing. They were all exploring different ideas about how to extend the Pok\xe9mon world into physical format."}),"\n",(0,n.jsx)(a.p,{children:'The TCG, when it launched in October 1996, didn\'t invent Pok\xe9mon cards. It standardized them into one format, one coherent system that could scale globally. In doing that, it closed off all the other directions the ecosystem had been moving. What we call "vintage Pok\xe9mon cards" today is just the branch of that exploration that survived.'})]})}function l(e={}){const{wrapper:a}={...(0,s.R)(),...e.components};return a?(0,n.jsx)(a,{...e,children:(0,n.jsx)(h,{...e})}):h(e)}},28453:(e,a,t)=>{t.d(a,{R:()=>r,x:()=>i});var o=t(96540);const n={},s=o.createContext(n);function r(e){const a=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(a):{...a,...e}},[a,e])}function i(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:r(e.components),o.createElement(s.Provider,{value:a},e.children)}},67870:e=>{e.exports=JSON.parse('{"permalink":"/blog/the-lost-era-of-pokemon-cards","editUrl":"https://github.com/DidierRLopes/my-website/tree/main/blog/2026-03-27-before-the-pokemon-tcg-the-lost-era-of-pokemon-cards.md","source":"@site/blog/2026-03-27-before-the-pokemon-tcg-the-lost-era-of-pokemon-cards.md","title":"The Lost Era of Pok\xe9mon Cards","description":"Most people think the Pok\xe9mon Trading Card Game is where it all started. It\'s not. Before the TCG became the global standard, Japan had an entire parallel ecosystem of Pok\xe9mon cards.","date":"2026-03-27T00:00:00.000Z","tags":[{"inline":true,"label":"pokemon","permalink":"/blog/tags/pokemon"},{"inline":true,"label":"collecting","permalink":"/blog/tags/collecting"},{"inline":true,"label":"pokemon-cards","permalink":"/blog/tags/pokemon-cards"}],"readingTime":11.98,"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"the-lost-era-of-pokemon-cards","title":"The Lost Era of Pok\xe9mon Cards","date":"2026-03-27T00:00:00.000Z","image":"/blog/2026-03-27-before-the-pokemon-tcg-the-lost-era-of-pokemon-cards.webp","tags":["pokemon","collecting","pokemon-cards"],"description":"Most people think the Pok\xe9mon Trading Card Game is where it all started. It\'s not. Before the TCG became the global standard, Japan had an entire parallel ecosystem of Pok\xe9mon cards.","hideSidebar":true},"unlisted":false,"nextItem":{"title":"The era of on-demand software","permalink":"/blog/the-era-of-on-demand-software"}}')}}]);